# {The new algorithm moderates edge distances by weighting each edge based on its frequency of usage in local optima tours and inversely to the square of the edge's usage, thus balancing reinforcement and diversification of routes.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    updated_edge_distance = np.copy(edge_distance)
    rows, cols = edge_n_used.shape

    # Compute a new adjustment factor for each edge based on its usage in optimal tours and inversely related to the square of its usage
    for i in range(rows):
        for j in range(cols):
            if edge_n_used[i, j] > 0:
                if (i, j) in local_opt_tours:
                    # Reduce distance if frequently used in local optima tours, but factor in the square of its usage
                    updated_edge_distance[i, j] *= (1 - 0.1 / (edge_n_used[i, j] ** 2))
                else:
                    # Increase distance to promote exploration, less strongly influenced by high usage
                    updated_edge_distance[i, j] *= (1 + 0.1 / (edge_n_used[i, j] ** 2))

    return updated_edge_distance

