# {The new algorithm dynamically adjusts edge distances by utilizing exponential decay for frequently used edges and an exponential boost for underused edges, promoting adaptability in achieving route optimality.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Parameters for exponential adjustment
    decay_factor = 0.05    # Decay for frequently used edges
    boost_factor = 0.05    # Boost for underused edges

    updated_edge_distance = np.copy(edge_distance)
    rows, cols = edge_n_used.shape

    for i in range(rows):
        for j in range(cols):
            if edge_n_used[i, j] > 0:
                # Apply exponential decay for frequently used edges
                updated_edge_distance[i, j] *= np.exp(decay_factor * edge_n_used[i, j])
            else:
                # Apply exponential boost for underused edges
                updated_edge_distance[i, j] *= np.exp(-boost_factor)

    return updated_edge_distance

import numpy as np

# {The new algorithm updates edge distances by applying a linear penalty to frequently used edges and a reward to underused edges, promoting exploration while avoiding short-term bias.}

def update_edge_distance(edge_distance, local_opt_tours, edge_n_used):
    # Parameters for linear adjustment
    penalty_factor = 0.1   # Penalty for frequently used edges
    reward_factor = 0.1    # Reward for underused edges

    updated_edge_distance = np.copy(edge_distance)
    rows, cols = edge_n_used.shape

    # Compute usage frequency adjustments
    for i in range(rows):
        for j in range(cols):
            if edge_n_used[i, j] > 0:
                # Apply a higher distance penalty for frequently used edges
                updated_edge_distance[i, j] += penalty_factor * edge_n_used[i, j]
            else:
                # Reward underused edges by reducing their distance
                updated_edge_distance[i, j] -= reward_factor

    # Ensure no negative distances
    updated_edge_distance = np.maximum(updated_edge_distance, 0)

    return updated_edge_distance
